#include <stdio.h>
#include <stdlib.h>
#include <sys/mount.h>
#include <errno.h>

int main(int argc, char *argv[]) {
    /*
     * int mount(const char *source, const char *target,
     *           const char *filesystemtype, unsigned long mountflags,
     *           const void *data);
     */

    const char *source = "/dev/sdb1";
    const char *target = "/mnt/usb";
    const char *fstype = "vfat";

    // Mount flags (MS_*) - combining multiple flags with OR
    unsigned long flags = MS_NOSUID | MS_NOEXEC | MS_NODEV;

    // Options string (filesystem-specific)
    const char *data = "uid=1000,gid=1000";

    int result = mount(source, target, fstype, flags, data);

    if (result == -1) {
        perror("Mount failed");
        printf("Error code: %d\n", errno);
        return 1;
    }

    printf("Successfully mounted %s at %s\n", source, target);

    // To unmount: use umount2() or umount() system call
    // int ret = umount2(target, MNT_FORCE);  // with flags
    // int ret = umount(target);               // simple unmount

    return 0;
}

/* Common mount flags (MS_*):
 * MS_RDONLY   - Mount read-only
 * MS_NOSUID   - Ignore setuid/setgid bits
 * MS_NOEXEC   - Disallow execution of binaries
 * MS_NODEV    - Don't interpret character/block devices
 * MS_REMOUNT  - Change mount options of existing mount
 * MS_BIND     - Create bind mount
 * MS_MOVE     - Move mount point
 */
